      const errorMessage = isStream ? `Worker error during stream generation: ${error.message}` : `Worker error during generation: ${error.message}`;
      cleanup();
      reject(createWorkerError(errorMessage, "runtime_error"));
      this.processNextInQueue(worker, mode);
